using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF9: HasIndex now throws for Cosmos — indexing is managed via Azure Portal/Bicep
            // EF9: Default discriminator property renamed from "Discriminator" to "$type"
            entity.HasDiscriminator<string>("Discriminator");
            // EF9: id no longer contains discriminator — preserve "Blog|1" format for existing docs
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

